def fused_lu_solve(A: torch.Tensor, b: torch.Tensor) -> torch.Tensor:
    n = A.shape[0]
    assert A.shape == (n, n), "Matrix A must be square"
    assert b.shape == (n,), "Vector b must be of length n"

    # Allocate output tensor
    x = torch.empty_like(b)

    # Create a copy of A for LU decomposition
    LU = A.clone().to(torch.float32)

    # Perform LU decomposition
    for k in range(n):
        # Find pivot
        pivot = k
        for i in range(k + 1, n):
            if abs(LU[i, k]) > abs(LU[pivot, k]):
                pivot = i

        # Swap rows if needed
        if pivot != k:
            LU[[k, pivot], :] = LU[[pivot, k], :]
            b[[k, pivot]] = b[[pivot, k]]

        # Check for singular matrix
        if abs(LU[k, k]) < 1e-12:
            raise ValueError("Matrix is singular")

        # Compute multipliers and update matrix
        for i in range(k + 1, n):
            LU[i, k] = LU[i, k] / LU[k, k]
            for j in range(k + 1, n):
                LU[i, j] = LU[i, j] - LU[i, k] * LU[k, j]

    # Forward substitution
    for i in range(n):
        for j in range(i):
            b[i] = b[i] - LU[i, j] * b[j]

    # Backward substitution
    for i in range(n - 1, -1, -1):
        for j in range(i + 1, n):
            b[i] = b[i] - LU[i, j] * b[j]
        b[i] = b[i] / LU[i, i]

    return b

